sql:
SELECT image_file
FROM satellite_imagery
WHERE cloud_cover < 10;

SELECT name, population
FROM urban_areas
WHERE name = 'Randall Manor';

SELECT layer_name, layer_type
FROM gis_layers
WHERE layer_type = 'polygon';

SELECT map_name, created_at
FROM maps
ORDER BY created_at DESC;

SELECT COUNT(*)
FROM urban_areas
WHERE population > 2000;

SELECT holc_grade, COUNT(*) AS number_of_areas
FROM urban_areas
GROUP BY holc_grade;

SELECT name, population, area_sq_km, last_update
FROM urban_areas
ORDER BY population DESC;

SELECT name, population
FROM urban_areas
ORDER BY population DESC;

SELECT AVG(s.cloud_cover) AS average_cloud_cover
FROM satellite_imagery s
INNER JOIN historical_data h ON strftime('%Y', s.date_acquired) = CAST(h.year AS TEXT);

external_knowledge:
- Significant cloudiness in this context refers to images with cloud cover more than 50%;
- The photographs mentioned are satellite images;
- Chronological order means presenting data from the earliest date to the latest date.
